+          <button class="btn btn-primary btn-sm" onclick="runReplayDemo()">Run Test</button>
+        </div>
+        <div id="replay-result">
+          <div class="text-dim" style="text-align:center;padding:32px 0;">Creates scopes, frees them, then verifies reuse follows LIFO order</div>
