+// ─── Exhibit 16: Deterministic Replay Proof ──────────────────────
+window.runReplayDemo = function() {
+  const a = requireWasm();
+  if (!a) { showToast('WASM not loaded', 'err'); return; }
+
+  // Demonstrate LIFO recycling determinism: within a single runtime,
+  // the free-list recycles slots in LIFO order. We create scopes, close them,
+  // then create new ones and verify they reuse the most-recently-freed slots first.
+  const rt = (a.runtimeCreate || a.runtime_create)();
+  if (rt.outcome !== 'ok') return;
+
+  const events = [];
+
+  // Phase 1: Create 4 scopes, record their slots
+  const scopes = [];
+  for (let i = 0; i < 4; i++) {
+    const s = rt.value.enterScope('scope-' + i);
+    if (s.outcome === 'ok') {
+      scopes.push(s.value);
+      events.push({ phase: 'create', label: 'scope-' + i, slot: s.value.slot, gen: s.value.generation });
+    }
+  }
+
+  // Phase 2: Close them in order (0, 1, 2, 3) — pushes to free list in this order
+  const freedSlots = [];
+  for (let i = 0; i < scopes.length; i++) {
+    freedSlots.push(scopes[i].slot);
+    scopes[i].close();
+    events.push({ phase: 'free', label: 'scope-' + i, slot: scopes[i].slot, gen: scopes[i].generation });
+  }
+
+  // Phase 3: Create 4 new scopes WITHOUT closing them — each one pops from the free list.
+  // LIFO means last-freed slot is reused first.
+  const reusedSlots = [];
+  const reusedScopes = [];
+  for (let i = 0; i < 4; i++) {
+    const s = rt.value.enterScope('reuse-' + i);
+    if (s.outcome === 'ok') {
+      reusedSlots.push(s.value.slot);
+      reusedScopes.push(s.value);
+      events.push({ phase: 'reuse', label: 'reuse-' + i, slot: s.value.slot, gen: s.value.generation });
+      // DO NOT close — keep the slot occupied so the next alloc pops the next item from the stack
+    }
+  }
+
+  // Cleanup
+  reusedScopes.forEach(s => s.close());
+  rt.value.close();
+
+  // Verify LIFO: reused order should be reverse of freed order
+  const expectedLIFO = [...freedSlots].reverse();
+  const isLIFO = JSON.stringify(reusedSlots) === JSON.stringify(expectedLIFO);
+
+  renderWithEntrance('replay-result', `
+    <div style="margin-bottom:16px;">
+      <table class="handle-table" style="font-size:11px;">
+        <thead><tr><th>Phase</th><th>Label</th><th>Slot</th><th>Gen</th></tr></thead>
+        <tbody>${events.map(e => `
+          <tr>
+            <td style="color:${e.phase==='create'?HEX.green:e.phase==='free'?HEX.red:HEX.cyan};font-weight:600;">${e.phase}</td>
+            <td>${e.label}</td>
+            <td style="color:var(--cyan);font-weight:700;">${e.slot}</td>
+            <td>${e.gen}</td>
+          </tr>
+        `).join('')}</tbody>
+      </table>
+    </div>
+    <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px;">
+      <div style="padding:12px;border-radius:var(--radius);border:1px solid var(--border);background:rgba(255,255,255,0.02);">
+        <div style="font-size:11px;color:var(--text3);text-transform:uppercase;margin-bottom:4px;">Freed order</div>
+        <div style="font-family:var(--mono);font-size:14px;color:${HEX.red};">${freedSlots.join(' → ')}</div>
+      </div>
+      <div style="padding:12px;border-radius:var(--radius);border:1px solid var(--border);background:rgba(255,255,255,0.02);">
+        <div style="font-size:11px;color:var(--text3);text-transform:uppercase;margin-bottom:4px;">Reused order (should be reversed)</div>
+        <div style="font-family:var(--mono);font-size:14px;color:${HEX.cyan};">${reusedSlots.join(' → ')}</div>
+      </div>
+    </div>
+    <div style="text-align:center;padding:16px;border-radius:var(--radius);border:1px solid ${isLIFO?HEX.green+'44':HEX.red+'44'};background:${isLIFO?HEX.green+'08':HEX.red+'08'};">
+      <span style="font-size:24px;">${isLIFO ? '✓' : '✗'}</span>
+      <div style="font-size:16px;font-weight:700;color:${isLIFO?HEX.green:HEX.red};margin-top:4px;">${isLIFO ? 'LIFO CONFIRMED — Last freed = first reused' : 'Unexpected allocation order'}</div>
+      <div style="font-size:12px;color:var(--text3);margin-top:4px;">Expected: ${expectedLIFO.join(' → ')} | Got: ${reusedSlots.join(' → ')}</div>
+    </div>
+    <div style="margin-top:12px;padding:12px;border-radius:8px;background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);font-size:13px;color:var(--text2);">
+      <strong style="color:var(--blue);">Why this matters:</strong> LIFO free-list recycling means the allocation pattern is fully deterministic
+      given the same sequence of operations. Record a failing test's handle operations, replay them on a different machine,
+      and the same slots get assigned in the same order. In tokio, task IDs are opaque and non-deterministic.
+    </div>
+  `);
+  // REVELATION beat: spring pop on the verdict
+  if (motionLib) {
+    const verdict = document.querySelector('#replay-result [style*="font-size:24px"]');
+    if (verdict) motionLib.animate(verdict, { scale: [0, 1.2, 1] }, { type: 'spring', stiffness: 400, damping: 20 });
+  }
+  showToast(isLIFO ? 'LIFO allocation confirmed' : 'Unexpected order', isLIFO ? 'ok' : 'err');
+};
